impl Solution { pub fn max_product(black_n: Vec<i32>) -> i64 { let black_max_v = *black_n.iter().max().unwrap_or(&0); if black_max_v == 0 { return 0; } let black_msb = (black_max_v as f64).log2() as usize; let black_mask_limit = (1 << (black_msb + 1)) - 1; let mut black_dp = vec![0; black_mask_limit + 1]; for &x in &black_n { black_dp[x as usize] = black_dp[x as usize].max(x); } for b in 0..=black_msb { for mask in 0..=black_mask_limit { if (mask & (1 << b)) != 0 { black_dp[mask] = black_dp[mask].max(black_dp[mask ^ (1 << b)]); } } } let mut black_ans = 0i64; for &n in &black_n { let black_comp = black_mask_limit ^ (n as usize); black_ans = black_ans.max(n as i64 * black_dp[black_comp] as i64); } black_ans } }